import React from "react";
import { theme, Row, Col, Card, Statistic, Typography, Space, Tag, Avatar, Progress, Flex, App, Divider, Empty } from "antd";
import { 
  ProjectOutlined, 
  FileDoneOutlined, 
  TeamOutlined, 
  DashboardOutlined,
  ClockCircleOutlined
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import { useTranslation } from "react-i18next";
import { getMockLabelingJobs } from "../../mocks/jobs";

const { useToken } = theme;
const { Title, Text } = Typography;

export default function LabelingDashboard() {
  const { token } = useToken();
  const { t } = useTranslation(["dashboard", "common"]);
  const mockJobs = React.useMemo(() => getMockLabelingJobs(t), [t]);

  const totalProjects = new Set(mockJobs.map((job) => job.prjNm)).size;
  const completedCount = mockJobs.reduce((sum, job) => sum + job.workCnt, 0);
  const activeManagers = new Set(mockJobs.map((job) => job.pmNm)).size;
  const averageProgress = mockJobs.length
    ? mockJobs.reduce((sum, job) => sum + job.progress, 0) / mockJobs.length
    : 0;

  const progressChartOption = {
    tooltip: { trigger: "axis", axisPointer: { type: "shadow" } },
    grid: { left: "3%", right: "4%", bottom: "3%", containLabel: true },
    xAxis: {
      type: "value",
      max: 100,
      axisLabel: { formatter: "{value}%" },
    },
    yAxis: {
      type: "category",
      data: mockJobs.map((job) => job.jobNm),
      axisLabel: { color: token.colorTextSecondary },
    },
    series: [
      {
        name: t("charts.progress"),
        type: "bar",
        data: mockJobs.map((job) => job.progress),
        barWidth: 18,
        itemStyle: {
          borderRadius: [0, 6, 6, 0],
          color: token.colorPrimary,
        },
        label: {
          show: true,
          position: "right",
          formatter: "{c}%",
          color: token.colorText,
        },
      },
    ],
  };

  const deadlineJobs = [...mockJobs]
    .sort((left, right) => new Date(left.expireDt).getTime() - new Date(right.expireDt).getTime())
    .slice(0, 3);

  const getStatusColor = (progress: number) => {
    if (progress >= 80) return token.colorSuccess;
    if (progress >= 30) return token.colorWarning;
    return token.colorError;
  };

  return (
    <div style={{ padding: "0 24px 24px 24px", background: token.colorBgLayout }}>
      <div style={{ marginBottom: 20 }}>
        <Title level={3}>{t("title")}</Title>
        <Text type="secondary">{t("subtitle")}</Text>
      </div>

      <Row gutter={[16, 16]}>
        <Col span={6}>
          <Card variant="borderless" styles={{ body: { padding: "20px" } }} style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }}>
            <Statistic
              title={t("summary.projects")}
              value={totalProjects}
              prefix={<ProjectOutlined style={{ color: token.colorPrimary, paddingRight: 8 }} />}
              suffix={<Text type="secondary" style={{ fontSize: 12 }}>{t("unitCases", { ns: "common" })}</Text>}
            />
            <div style={{ marginTop: 8 }}><Text type="secondary" style={{ fontSize: 12 }}>{t("summary.projectsHint")}</Text></div>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" styles={{ body: { padding: "20px" } }} style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }}>
            <Statistic
              title={t("summary.todayCount")}
              value={completedCount}
              prefix={<FileDoneOutlined style={{ color: token.colorSuccess, paddingRight: 8 }} />}
              suffix={<Text type="secondary" style={{ fontSize: 12 }}>{t("unitItems", { ns: "common" })}</Text>}
            />
            <div style={{ marginTop: 8 }}><Text type="secondary" style={{ fontSize: 12 }}>{t("summary.todayCountHint")}</Text></div>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" styles={{ body: { padding: "20px" } }} style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }}>
            <Statistic
              title={t("summary.activeWorkers")}
              value={activeManagers}
              prefix={<TeamOutlined style={{ color: token.colorWarning, paddingRight: 8 }} />}
              suffix={<Text type="secondary" style={{ fontSize: 12 }}>{t("unitPersons", { ns: "common" })}</Text>}
            />
            <div style={{ marginTop: 8 }}><Text type="secondary" style={{ fontSize: 12 }}>{t("summary.activeWorkersHint")}</Text></div>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" styles={{ body: { padding: "20px" } }} style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }}>
            <Statistic
              title={t("summary.avgProgress")}
              value={averageProgress}
              precision={2}
              prefix={<DashboardOutlined style={{ color: token.colorInfo, paddingRight: 8 }} />}
              suffix={<Text type="secondary" style={{ fontSize: 12 }}>%</Text>}
            />
            <div style={{ marginTop: 8 }}><Text type="secondary" style={{ fontSize: 12 }}>{t("summary.avgProgressHint")}</Text></div>
          </Card>
        </Col>
      </Row>

      <Row gutter={[16, 16]} style={{ marginTop: 16 }}>
        <Col span={16}>
          <Card variant="borderless" title={t("tasks.title")} style={{ borderRadius: 12, boxShadow: token.boxShadowTertiary }}>
            <div style={{ maxHeight: 320, overflow: "auto" }}>
            <div style={{ maxHeight: 320, overflow: "auto", paddingRight: 8 }}>
              <Flex vertical>
                {mockJobs.map((job, idx) => (
                  <div key={job.jobNm}>
                    <div style={{ width: "100%", padding: "12px 0" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", gap: 12, marginBottom: 4 }}>
                        <div>
                          <Text strong>{job.prjNm}</Text>
                          <div><Text type="secondary">{job.taskNm}</Text></div>
                        </div>
                        <Tag color={job.progress >= 80 ? "green" : job.progress >= 30 ? "orange" : "red"}>{job.pmNm}</Tag>
                      </div>
                      <Progress
                        percent={job.progress}
                        size="small"
                        strokeColor={getStatusColor(job.progress)}
                        status={job.progress === 100 ? "success" : "active"}
                      />
                      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 6 }}>
                        <Text type="secondary">{job.jobNm}</Text>
                        <Space size={4}>
                          <Text type="secondary">{job.workCnt} / {job.goalCnt}</Text>
                          <Text type="secondary" style={{ fontSize: 10 }}>{t("unit", { ns: "common" })}</Text>
                        </Space>
                      </div>
                    </div>
                    {idx < mockJobs.length - 1 && <Divider style={{ margin: 0 }} />}
                  </div>
                ))}
                {mockJobs.length === 0 && <Empty description={t("noObjects", { ns: "common" })} />}
              </Flex>
            </div>
            </div>
          </Card>
        </Col>
        <Col span={8}>
          <Card variant="borderless" title={t("charts.progress")} style={{ borderRadius: 12, height: "100%", boxShadow: token.boxShadowTertiary }}>
            <ReactECharts option={progressChartOption} style={{ height: 320 }} />
          </Card>
        </Col>
      </Row>

      <Row gutter={[16, 16]} style={{ marginTop: 16 }}>
        <Col span={24}>
          <Card variant="borderless" title={t("tasks.deadlineTitle")} style={{ borderRadius: 12, height: "100%", boxShadow: token.boxShadowTertiary }}>
            <Flex vertical>
              {deadlineJobs.map((job, idx) => (
                <div key={job.prjNm + idx}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 0" }}>
                    <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
                      <Avatar icon={<ClockCircleOutlined />} style={{ background: token.colorPrimary }} />
                      <div>
                        <div><Space><span>{job.prjNm}</span><Tag>{job.expireDt}</Tag></Space></div>
                        <div style={{ color: token.colorTextSecondary, fontSize: 13 }}>{job.taskNm} / {job.jobNm}</div>
                      </div>
                    </div>
                    <div style={{ minWidth: 120, textAlign: "right" }}>
                      <Text strong>{job.progress}%</Text>
                      <div>
                        <Text type="secondary">{job.workCnt} / {job.goalCnt}</Text>
                        <Text type="secondary" style={{ fontSize: 10, marginLeft: 4 }}>{t("unit", { ns: "common" })}</Text>
                      </div>
                    </div>
                  </div>
                  {idx < deadlineJobs.length - 1 && <Divider style={{ margin: 0 }} />}
                </div>
              ))}
            </Flex>
          </Card>
        </Col>
      </Row>
    </div>
  );
}
